function makeItQuack(obj) {
  // The function doesn't care if 'obj' is a Dog, a Cat, or a Robot.
  // It only cares that 'obj' has a 'speak' method.
  if (typeof obj.speak === 'function') {
    obj.speak();
  }
}

class Dog {
  speak() { console.log("Woof!"); }
}

class Robot {
  speak() { console.log("Beep Boop!"); }
}

**Example (TypeScript - Static):**
```typescript
function makeItQuack(obj: { speak: () => void }) {
  obj.speak();
}

class Dog {
  speak() { console.log("Woof!"); }
}

// ❌ ERROR: Argument of type 'string' is not assignable to parameter of type '{ speak: () => void; }'
makeItQuack("I am a string"); 
